174	export const line = (start: Position, end: Position): readonly Position[] => {
175	  assertPosition(start, "start");
176	  assertPosition(end, "end");
177	
178	  const cells: Position[] = [];
179	  let x = start.x;
180	  let y = start.y;
181	  const dx = Math.abs(end.x - start.x);
182	  const sx = start.x < end.x ? 1 : -1;
183	  const dy = -Math.abs(end.y - start.y);
184	  const sy = start.y < end.y ? 1 : -1;
185	  let error = dx + dy;
186	
187	  while (true) {
188	    cells.push({ x, y });
189	
190	    if (x === end.x && y === end.y) {
191	      return cells;
192	    }
193	
194	    const doubledError = 2 * error;
195	
196	    if (doubledError >= dy) {
197	      error += dy;
198	      x += sx;
199	    }
200	
201	    if (doubledError <= dx) {
202	      error += dx;
203	      y += sy;
204	    }
205	  }
206	};
