216	  const cells: Position[] = [];
217	  const radiusSquared = radius * radius;
218	
219	  for (let y = origin.y - radius; y <= origin.y + radius; y += 1) {
220	    for (let x = origin.x - radius; x <= origin.x + radius; x += 1) {
221	      const position = { x, y };
222	      const dx = x - origin.x;
223	      const dy = y - origin.y;
224	
225	      if (
226	        dx * dx + dy * dy <= radiusSquared &&
227	        (bounds === undefined || inBounds(bounds, position))
228	      ) {
229	        cells.push(position);
230	      }
231	    }
232	  }
233	
234	  return cells;
235	};
