 81	  const isTransparent = options.isTransparent ?? defaultTransparency;
 82	
 83	  for (const direction of ["north", "south", "east", "west"] as const) {
 84	    scanRow(
 85	      grid,
 86	      origin,
 87	      options.radius,
 88	      direction,
 89	      { depth: 1, startSlope: -1, endSlope: 1 },
 90	      visible,
 91	      isTransparent,
 92	    );
 93	  }
 94	
 95	  return visible;
 96	}
