130	export const updateFogMemory = (
131	  fog: FogMemory,
132	  grid: TileGrid,
133	  visible: ReadonlySet<number>,
134	): FogMemory => {
135	  assertFogMatchesGrid(fog, grid);
136	
137	  return {
138	    ownerId: fog.ownerId,
139	    width: fog.width,
140	    height: fog.height,
141	    tiles: fog.tiles.map((memory, index) => {
142	      if (visible.has(index)) {
143	        return {
144	          state: "visible",
145	          rememberedTile: cloneTile(getTileAtIndex(grid, index)),
146	        };
147	      }
148	
149	      if (memory.state === "visible") {
150	        return {
151	          state: "remembered",
152	          rememberedTile:
153	            memory.rememberedTile === null
154	              ? null
155	              : cloneTile(memory.rememberedTile),
156	        };
157	      }
158	
159	      return {
160	        state: memory.state,
161	        rememberedTile:
162	          memory.rememberedTile === null
163	            ? null
164	            : cloneTile(memory.rememberedTile),
165	      };
166	    }),
167	  };
168	};
