181	const scanRow = (
182	  grid: TileGrid,
183	  origin: Position,
184	  radius: number,
185	  direction: CardinalDirection,
186	  row: ShadowcastRow,
187	  visible: Set<number>,
188	  isTransparent: TransparencyPredicate,
189	): void => {
190	  if (row.depth > radius) {
191	    return;
192	  }
193	
194	  let startSlope = row.startSlope;
195	  let previousBlocking: boolean | null = null;
196	
197	  for (
198	    let column = roundTiesUp(row.depth * row.startSlope);
199	    column <= roundTiesDown(row.depth * row.endSlope);
200	    column += 1
201	  ) {
202	    const position = transformQuadrant(origin, direction, row.depth, column);
203	    const positionInBounds = inBounds(grid, position);
204	    const tileBlocks =
205	      positionInBounds && !isTransparent(getTile(grid, position), position, grid);
206	    const blocking = !positionInBounds || tileBlocks;
207	
208	    if (
209	      positionInBounds &&
210	      distanceSquared(origin, position) <= radius * radius &&
211	      (tileBlocks || isSymmetric(row, column))
212	    ) {
213	      visible.add(idx(grid, position));
214	    }
215	
216	    if (previousBlocking === true && !blocking) {
217	      startSlope = slope(row.depth, column);
218	    }
219	
220	    if (previousBlocking === false && blocking) {
221	      scanRow(
222	        grid,
223	        origin,
224	        radius,
225	        direction,
226	        {
227	          depth: row.depth + 1,
228	          startSlope,
229	          endSlope: slope(row.depth, column),
230	        },
231	        visible,
232	        isTransparent,
233	      );
234	    }
235	
236	    previousBlocking = blocking;
237	  }
238	
239	  if (previousBlocking === false) {
240	    scanRow(
241	      grid,
242	      origin,
243	      radius,
244	      direction,
245	      {
246	        depth: row.depth + 1,
247	        startSlope,
248	        endSlope: row.endSlope,
249	      },
250	      visible,
251	      isTransparent,
252	    );
253	  }
254	};
