256	const visibleCellsForRadiusOrOptions = (
257	  grid: TileGrid,
258	  origin: Position,
259	  radiusOrOptions: number | VisibleCellsOptions,
260	): ReadonlySet<number> =>
261	  typeof radiusOrOptions === "number"
262	    ? visibleCells(grid, origin, radiusOrOptions)
263	    : visibleCells(grid, origin, radiusOrOptions);
264	
265	const defaultTransparency: TransparencyPredicate = (tile) =>
266	  isTransparentTile(tile);
267	
268	const transformQuadrant = (
269	  origin: Position,
270	  direction: CardinalDirection,
271	  depth: number,
272	  column: number,
273	): Position => {
274	  switch (direction) {
275	    case "north":
276	      return { x: origin.x + column, y: origin.y - depth };
277	    case "south":
278	      return { x: origin.x + column, y: origin.y + depth };
279	    case "east":
280	      return { x: origin.x + depth, y: origin.y + column };
281	    case "west":
282	      return { x: origin.x - depth, y: origin.y + column };
283	  }
284	};
285	
286	const isSymmetric = (row: ShadowcastRow, column: number): boolean =>
287	  column >= row.depth * row.startSlope &&
288	  column <= row.depth * row.endSlope;
289	
290	const slope = (depth: number, column: number): number =>
291	  (2 * column - 1) / (2 * depth);
292	
293	const roundTiesUp = (value: number): number => Math.floor(value + 0.5);
294	
295	const roundTiesDown = (value: number): number => Math.ceil(value - 0.5);
296	
297	const assertRadius = (radius: number): void => {
298	  if (!Number.isSafeInteger(radius) || radius < 0) {
299	    throw new RangeError("radius must be a non-negative safe integer");
300	  }
301	};
302	
303	const assertFogMatchesGrid = (fog: FogMemory, grid: TileGrid): void => {
304	  if (
305	    fog.width !== grid.width ||
306	    fog.height !== grid.height ||
307	    fog.tiles.length !== grid.tiles.length
308	  ) {
309	    throw new RangeError("fog memory dimensions must match the grid");
310	  }
311	};

