178	type ParsedMap = {
179	  readonly grid: TileGrid;
180	  readonly markers: ReadonlyMap<string, Position>;
181	};
182	
183	const parseMap = (source: string): ParsedMap => {
184	  const rows = source.trim().split("\n");
185	  const width = rows[0]?.length ?? 0;
186	  const tiles: Tile[] = [];
187	  const markerEntries: [string, Position][] = [];
188	
189	  for (let y = 0; y < rows.length; y += 1) {
190	    const row = rows[y];
191	
192	    if (row === undefined || row.length !== width) {
193	      throw new Error("fixture rows must have equal width");
194	    }
195	
196	    for (let x = 0; x < row.length; x += 1) {
197	      const character = row[x];
198	      const position = { x, y };
199	      const tile = tileForCharacter(character);
200	
201	      if (character !== undefined && /[A-Z@]/u.test(character)) {
202	        markerEntries.push([character, position]);
203	      }
204	
205	      tiles.push(tile);
206	    }
207	  }
208	
209	  return {
210	    grid: createTileGrid({ width, height: rows.length, tiles }),
211	    markers: new Map(markerEntries),
212	  };
213	};
214	
215	const tileForCharacter = (character: string | undefined): Tile => {
216	  switch (character) {
217	    case "#":
218	    case "W":
219	      return createTile(Terrain.Wall);
220	    case "~":
221	      return createTile(Terrain.Water);
222	    case "+":
223	      return createTile(Terrain.Door, "closed");
224	    case "/":
225	      return createTile(Terrain.Door, "open");
226	    case ">":
227	      return createTile(Terrain.StairsDown);
228	    case "<":
229	      return createTile(Terrain.Entrance);
230	    case ".":
231	    case "@":
232	    case "H":
233	      return createTile(Terrain.Floor);
234	    default:
235	      throw new Error(`unsupported fixture character ${String(character)}`);
236	  }
237	};
238	
239	const marker = (
240	  markers: ReadonlyMap<string, Position>,
241	  name: string,
242	): Position => {
243	  const position = markers.get(name);
244	
245	  if (position === undefined) {
246	    throw new Error(`missing marker ${name}`);
247	  }
248	
249	  return position;
250	};
