252	const visiblePattern = (
253	  grid: TileGrid,
254	  visible: ReadonlySet<number>,
255	  origin: Position,
256	): string => {
257	  const rows: string[] = [];
258	
259	  for (let y = 0; y < grid.height; y += 1) {
260	    let row = "";
261	
262	    for (let x = 0; x < grid.width; x += 1) {
263	      const position = { x, y };
264	      const tile = getTile(grid, position);
265	      const index = idx(grid, position);
266	
267	      if (position.x === origin.x && position.y === origin.y) {
268	        row += "@";
269	      } else if (!visible.has(index)) {
270	        row += ".";
271	      } else if (tile.terrain === Terrain.Wall) {
272	        row += "#";
273	      } else {
274	        row += "v";
275	      }
276	    }
277	
278	    rows.push(row);
279	  }
280	
281	  return rows.join("\n");
282	};
